query:
UPDATE collateralItems ci
SET matchCount = (
  SELECT COUNT(*) FROM collateralProjectMatches cpm WHERE cpm.collateralId = ci.id
)
WHERE ci.id BETWEEN 120001 AND 120007;

SELECT id, name, matchCount FROM collateralItems WHERE id BETWEEN 120001 AND 120007;

